import React, { useEffect, useState } from 'react';
import { Asset, AssetInput, AssetState, Product, Vendor, createAsset, updateAsset } from '../services/api';

interface AssetFormProps {
  editing: Asset | null;
  mode: 'create' | 'edit' | 'view';
  products: Product[];
  vendors: Vendor[];
  assetStates: AssetState[];
  selectedProductTypeId: string;
  saving?: boolean;
  onBack: () => void;
  onSave: () => void;
}

const emptyAssetInput: AssetInput = {
  name: '',
  product_id: '',
  serial_number: '',
  asset_tag: '',
  vendor_id: '',
  barcode_qr_code: '',
  purchase_cost: '',
  acquisition_date: '',
  expiry_date: '',
  warranty_expiry_date: '',
  location: '',
  asset_state_id: '',
  assigned_user: '',
  department: '',
  associated_to: '',
  site: '',
  state_comments: '',
};

const formatDateValue = (value: string | null | undefined) => {
  if (!value) {
    return '';
  }

  return value.slice(0, 10);
};

const AssetForm: React.FC<AssetFormProps> = ({
  editing,
  mode,
  products,
  vendors,
  assetStates,
  selectedProductTypeId,
  saving,
  onBack,
  onSave,
}) => {
  const [formData, setFormData] = useState<AssetInput>(emptyAssetInput);
  const readonly = mode === 'view';

  useEffect(() => {
    if (editing) {
      setFormData({
        name: editing.name || '',
        product_id: editing.product_id || '',
        serial_number: editing.serial_number || '',
        asset_tag: editing.asset_tag || '',
        vendor_id: editing.vendor_id || '',
        barcode_qr_code: editing.barcode_qr_code || '',
        purchase_cost: editing.purchase_cost || '',
        acquisition_date: formatDateValue(editing.acquisition_date),
        expiry_date: formatDateValue(editing.expiry_date),
        warranty_expiry_date: formatDateValue(editing.warranty_expiry_date),
        location: editing.location || '',
        asset_state_id: editing.asset_state_id || '',
        assigned_user: editing.assigned_user || '',
        department: editing.department || '',
        associated_to: editing.associated_to || '',
        site: editing.site || '',
        state_comments: editing.state_comments || '',
      });
    } else {
      setFormData(emptyAssetInput);
    }
  }, [editing]);

  const availableProducts = selectedProductTypeId
    ? products.filter((product) => product.product_type_id === selectedProductTypeId || product.id === formData.product_id)
    : products;

  const handleChange = (event: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    setFormData((currentData) => ({ ...currentData, [event.target.name]: event.target.value }));
  };

  const handleSave = async (continueEditing = false) => {
    if (saving || readonly) {
      return;
    }

    try {
      if (editing) {
        await updateAsset(editing.id, formData);
      } else {
        await createAsset(formData);
      }

      onSave();
      if (!continueEditing) {
        onBack();
      }
    } catch (error) {
      console.error('Error saving asset:', error);
    }
  };

  const inputClassName =
    'w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm text-slate-900 shadow-sm focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-slate-100';

  return (
    <div className="space-y-4">
      <button type="button" onClick={onBack} className="inline-flex items-center gap-2 text-sm text-slate-700 hover:text-slate-950">
        <svg className="h-4 w-4" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
          <path d="M10 3L5 8L10 13" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" />
        </svg>
        Back To List
      </button>

      <div className="rounded-lg border border-slate-200 bg-white p-6 shadow-sm">
        <div className="grid grid-cols-1 gap-x-7 gap-y-4 lg:grid-cols-2">
          <label className="grid grid-cols-[130px_minmax(0,1fr)] items-center gap-4 text-sm font-medium text-slate-700">
            <span>Name<span className="text-red-500">*</span></span>
            <input name="name" value={formData.name} onChange={handleChange} disabled={readonly} placeholder="Enter asset name" className={inputClassName} />
          </label>

          <label className="grid grid-cols-[130px_minmax(0,1fr)] items-center gap-4 text-sm font-medium text-slate-700">
            <span>Asset Product<span className="text-red-500">*</span></span>
            <select name="product_id" value={formData.product_id} onChange={handleChange} disabled={readonly} className={inputClassName}>
              <option value="">Select asset product</option>
              {availableProducts.map((product) => (
                <option key={product.id} value={product.id}>
                  {product.name}
                </option>
              ))}
            </select>
          </label>
        </div>

        <div className="my-6 border-t border-slate-200"></div>
        <div className="mb-4 text-sm font-semibold text-slate-900">Asset Details</div>

        <div className="grid grid-cols-1 gap-x-7 gap-y-3 lg:grid-cols-2">
          <label className="grid grid-cols-[130px_minmax(0,1fr)] items-center gap-4 text-sm font-medium text-slate-700">
            <span>Serial Number</span>
            <input name="serial_number" value={formData.serial_number} onChange={handleChange} disabled={readonly} placeholder="enter serial number" className={inputClassName} />
          </label>
          <label className="grid grid-cols-[130px_minmax(0,1fr)] items-center gap-4 text-sm font-medium text-slate-700">
            <span>Asset Tag</span>
            <input name="asset_tag" value={formData.asset_tag} onChange={handleChange} disabled={readonly} placeholder="enter asset tag" className={inputClassName} />
          </label>
          <label className="grid grid-cols-[130px_minmax(0,1fr)] items-center gap-4 text-sm font-medium text-slate-700">
            <span>Vendor</span>
            <select name="vendor_id" value={formData.vendor_id} onChange={handleChange} disabled={readonly} className={inputClassName}>
              <option value="">Select vendor</option>
              {vendors.map((vendor) => (
                <option key={vendor.id} value={String(vendor.id)}>
                  {vendor.name}
                </option>
              ))}
            </select>
          </label>
          <label className="grid grid-cols-[130px_minmax(0,1fr)] items-center gap-4 text-sm font-medium text-slate-700">
            <span>Barcode/QR Code</span>
            <input name="barcode_qr_code" value={formData.barcode_qr_code} onChange={handleChange} disabled={readonly} placeholder="enter barcode/qr code" className={inputClassName} />
          </label>
          <label className="grid grid-cols-[130px_minmax(0,1fr)] items-center gap-4 text-sm font-medium text-slate-700">
            <span>Purchase Cost</span>
            <input name="purchase_cost" value={formData.purchase_cost} onChange={handleChange} disabled={readonly} placeholder="Enter purchase cost" className={inputClassName} />
          </label>
          <label className="grid grid-cols-[130px_minmax(0,1fr)] items-center gap-4 text-sm font-medium text-slate-700">
            <span>Acquisition Date</span>
            <input type="date" name="acquisition_date" value={formData.acquisition_date} onChange={handleChange} disabled={readonly} className={inputClassName} />
          </label>
          <label className="grid grid-cols-[130px_minmax(0,1fr)] items-center gap-4 text-sm font-medium text-slate-700">
            <span>Expiry Date</span>
            <input type="date" name="expiry_date" value={formData.expiry_date} onChange={handleChange} disabled={readonly} className={inputClassName} />
          </label>
          <label className="grid grid-cols-[130px_minmax(0,1fr)] items-center gap-4 text-sm font-medium text-slate-700">
            <span>Warranty Expiry Date</span>
            <input type="date" name="warranty_expiry_date" value={formData.warranty_expiry_date} onChange={handleChange} disabled={readonly} className={inputClassName} />
          </label>
          <label className="grid grid-cols-[130px_minmax(0,1fr)] items-center gap-4 text-sm font-medium text-slate-700 lg:col-span-1">
            <span>Location</span>
            <input name="location" value={formData.location} onChange={handleChange} disabled={readonly} placeholder="enter location" className={inputClassName} />
          </label>
        </div>

        <div className="my-6 border-t border-slate-200"></div>
        <div className="mb-4 text-sm font-semibold text-slate-900">Asset State</div>

        <div className="grid grid-cols-1 gap-x-7 gap-y-3 lg:grid-cols-2">
          <label className="grid grid-cols-[130px_minmax(0,1fr)] items-center gap-4 text-sm font-medium text-slate-700">
            <span>Asset Is Currently</span>
            <select name="asset_state_id" value={formData.asset_state_id} onChange={handleChange} disabled={readonly} className={inputClassName}>
              <option value="">Select Asset State</option>
              {assetStates.map((assetState) => (
                <option key={assetState.id} value={assetState.id}>
                  {assetState.name}
                </option>
              ))}
            </select>
          </label>
          <label className="grid grid-cols-[130px_minmax(0,1fr)] items-center gap-4 text-sm font-medium text-slate-700">
            <span>User</span>
            <input name="assigned_user" value={formData.assigned_user} onChange={handleChange} disabled={readonly} placeholder="enter user" className={inputClassName} />
          </label>
          <label className="grid grid-cols-[130px_minmax(0,1fr)] items-center gap-4 text-sm font-medium text-slate-700">
            <span>Department</span>
            <input name="department" value={formData.department} onChange={handleChange} disabled={readonly} placeholder="enter department" className={inputClassName} />
          </label>
          <label className="grid grid-cols-[130px_minmax(0,1fr)] items-center gap-4 text-sm font-medium text-slate-700">
            <span>Associated To</span>
            <input name="associated_to" value={formData.associated_to} onChange={handleChange} disabled={readonly} placeholder="enter associated to" className={inputClassName} />
          </label>
          <label className="grid grid-cols-[130px_minmax(0,1fr)] items-center gap-4 text-sm font-medium text-slate-700">
            <span>Site</span>
            <input name="site" value={formData.site} onChange={handleChange} disabled={readonly} placeholder="enter site" className={inputClassName} />
          </label>
          <label className="grid grid-cols-[130px_minmax(0,1fr)] items-center gap-4 text-sm font-medium text-slate-700">
            <span>State Comments</span>
            <input name="state_comments" value={formData.state_comments} onChange={handleChange} disabled={readonly} placeholder="enter state comments" className={inputClassName} />
          </label>
        </div>

        {!readonly && (
          <div className="mt-6 flex justify-center gap-3">
            <button
              type="button"
              onClick={() => handleSave(false)}
              disabled={saving}
              className="rounded-md bg-blue-600 px-5 py-2 text-sm font-semibold text-white hover:bg-blue-700 disabled:opacity-60"
            >
              Save
            </button>
            <button
              type="button"
              onClick={() => handleSave(true)}
              disabled={saving}
              className="rounded-md bg-blue-600 px-5 py-2 text-sm font-semibold text-white hover:bg-blue-700 disabled:opacity-60"
            >
              Save and Continue Edit
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default AssetForm;
